import{_ as e,o as a,c as r,a2 as d}from"./chunks/framework.BYlK8ftn.js";const p=JSON.parse('{"title":"The Salt Road of Velya","description":"","frontmatter":{},"headers":[],"relativePath":"guide/worlds/velya-salt-road.md","filePath":"guide/worlds/velya-salt-road.md","lastUpdated":1781991869000}'),o={name:"guide/worlds/velya-salt-road.md"};function s(l,t,n,i,c,h){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="the-salt-road-of-velya" tabindex="-1">The Salt Road of Velya <a class="header-anchor" href="#the-salt-road-of-velya" aria-label="Permalink to &quot;The Salt Road of Velya&quot;">​</a></h1><p><strong>Zone role:</strong> Human lands, trade corridor, first caravan-robbery map.</p><p><strong>Design promise:</strong> A readable open road where the player can learn the caravan loop: spot the route, read the escort, choose an approach, strike or protect, then deal with faction consequences.</p><h2 id="lore" tabindex="-1">Lore <a class="header-anchor" href="#lore" aria-label="Permalink to &quot;Lore&quot;">​</a></h2><p>Velya began as a salt road between three human towns. Each town maintained a different piece of the route, so the road is full of mismatched stones, old boundary markers, patched wells, and shrines to local saints. It was neutral by habit, not by law: merchants paid small tolls, farmers sold water, and guards looked away when smugglers used the hedges after dusk.</p><p>The Empire changed the road without conquering it. First came a ledger clerk at the eastern gate. Then came soldiers to protect the ledger. Then came confiscated wagons, &quot;temporary&quot; barriers, and a gallows frame still officially called a sign post. Forest elves strike from the black pines when axes arrive in the caravan loads. Mountain scouts take bribes from both sides and report to the broken watchtower. Everyone still calls Velya neutral because admitting otherwise would force the towns to choose a war.</p><h2 id="mood-and-visual-language" tabindex="-1">Mood and visual language <a class="header-anchor" href="#mood-and-visual-language" aria-label="Permalink to &quot;Mood and visual language&quot;">​</a></h2><ul><li>Dust, low sun, pale road stones, yellow grass, torn banners.</li><li>Horizon landmarks are critical: the watchtower, toll gate, and burned inn should always orient the player.</li><li>The map must feel wide enough to leave the road but never so open that the caravan route disappears.</li><li>Human props should look repaired and reused; Empire props should be straight, numbered, and intrusive.</li></ul><h2 id="player-facing-flow" tabindex="-1">Player-facing flow <a class="header-anchor" href="#player-facing-flow" aria-label="Permalink to &quot;Player-facing flow&quot;">​</a></h2><ol><li>Spawn near the burned coaching inn with the road visible in both directions.</li><li>See or hear a caravan approaching before enemies engage.</li><li>Pick one of three approaches: road confrontation, pine ambush, or tower overlook.</li><li>Resolve the caravan event: guard it, rob it, or let another faction hit it.</li><li>Carry loot or reputation consequences toward the toll gate, shrine, or farms.</li></ol><h2 id="_20-by-20-text-map" tabindex="-1">20-by-20 text map <a class="header-anchor" href="#_20-by-20-text-map" aria-label="Permalink to &quot;20-by-20 text map&quot;">​</a></h2><p>Each row contains 20 cells. North is row 01, west is column 01.</p><table tabindex="0"><thead><tr><th>Symbol</th><th>Meaning</th></tr></thead><tbody><tr><td><code>.</code></td><td>Open grass or scrub</td></tr><tr><td><code>R</code></td><td>Main salt road</td></tr><tr><td><code>F</code></td><td>Farms and field props</td></tr><tr><td><code>H</code></td><td>Hedges, fences, low cover</td></tr><tr><td><code>P</code></td><td>Black pine ambush trees</td></tr><tr><td><code>D</code></td><td>Dry riverbed</td></tr><tr><td><code>I</code></td><td>Burned coaching inn / spawn</td></tr><tr><td><code>S</code></td><td>Saint Miro&#39;s shrine</td></tr><tr><td><code>T</code></td><td>Empire toll gate</td></tr><tr><td><code>W</code></td><td>Old watchtower</td></tr><tr><td><code>O</code></td><td>Rocky overlook</td></tr><tr><td><code>C</code></td><td>Caravan staging / wagon stop</td></tr><tr><td><code>X</code></td><td>Road barrier or blockade</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Row</th><th>20-cell map</th></tr></thead><tbody><tr><td>01</td><td><code>..............TTTT..</code></td></tr><tr><td>02</td><td><code>............RRRTTTX.</code></td></tr><tr><td>03</td><td><code>..........RRR...HHH.</code></td></tr><tr><td>04</td><td><code>........RRR.....HFF.</code></td></tr><tr><td>05</td><td><code>......RRR.....SS.FF.</code></td></tr><tr><td>06</td><td><code>PP..RRR......SS..FF.</code></td></tr><tr><td>07</td><td><code>PP.RR......HHH......</code></td></tr><tr><td>08</td><td><code>PPRR....DDDDHH......</code></td></tr><tr><td>09</td><td><code>.RR...DDDDDD....OO..</code></td></tr><tr><td>10</td><td><code>.R...DD..C.DD...OO..</code></td></tr><tr><td>11</td><td><code>RR.....CCCCDD.......</code></td></tr><tr><td>12</td><td><code>R....HHH..DD....WWW.</code></td></tr><tr><td>13</td><td><code>R...HH....D.....WWW.</code></td></tr><tr><td>14</td><td><code>RR..............W...</code></td></tr><tr><td>15</td><td><code>.RR....I...........P</code></td></tr><tr><td>16</td><td><code>..RR...I...HH.....PP</code></td></tr><tr><td>17</td><td><code>...RR..I..HHH....PPP</code></td></tr><tr><td>18</td><td><code>FF..RR....HH.....PPP</code></td></tr><tr><td>19</td><td><code>FFF..RR...........PP</code></td></tr><tr><td>20</td><td><code>FFFF..RR............</code></td></tr></tbody></table><h2 id="landmark-briefs" tabindex="-1">Landmark briefs <a class="header-anchor" href="#landmark-briefs" aria-label="Permalink to &quot;Landmark briefs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Landmark</th><th>Player use</th><th>Implementation notes</th></tr></thead><tbody><tr><td>Burned coaching inn</td><td>Spawn, safe tutorial space, later merchant shell</td><td>Keep the roof collapsed so the player can see through it; use warm ash colors against pale grass.</td></tr><tr><td>Saint Miro&#39;s shrine</td><td>Midpoint marker, possible save fiction</td><td>Place on a slight rise so it is visible over hedges; keep combat space around it circular.</td></tr><tr><td>Broken toll gate</td><td>Empire checkpoint and escalation point</td><td>Build as two lane barriers plus a ledger table; soldiers need clear patrol points.</td></tr><tr><td>Old watchtower</td><td>Ambush overlook and villain scout perch</td><td>The climb can be blocked in the first pass; it still needs a strong silhouette.</td></tr><tr><td>Dry riverbed</td><td>Natural arena around caravans</td><td>Use shallow banks and stones for cover without trapping the controller.</td></tr></tbody></table><h2 id="faction-pressure" tabindex="-1">Faction pressure <a class="header-anchor" href="#faction-pressure" aria-label="Permalink to &quot;Faction pressure&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Faction</th><th>Presence</th><th>Behavior</th></tr></thead><tbody><tr><td>Human townsfolk</td><td>Farms, inn ruins, water carts</td><td>Neutral by default, flee from combat, later provide rumors and prices.</td></tr><tr><td>Empire</td><td>Toll gate, patrols near barriers</td><td>Searches wagons, becomes hostile if stolen cargo is visible.</td></tr><tr><td>Forest Elves</td><td>Pine pockets west of the road</td><td>Ambushes caravans carrying timber or Empire weapons.</td></tr><tr><td>Villain scouts</td><td>Watchtower and overlook</td><td>Observes fights, retreats with information if not stopped.</td></tr></tbody></table><h2 id="encounter-set-pieces" tabindex="-1">Encounter set pieces <a class="header-anchor" href="#encounter-set-pieces" aria-label="Permalink to &quot;Encounter set pieces&quot;">​</a></h2><ul><li><strong>First caravan pass:</strong> one wagon, two guards, slow road movement, no faction complication unless the player attacks.</li><li><strong>Treefall blockade:</strong> elves drop a pine near the dry riverbed, stopping the caravan and creating a three-sided fight.</li><li><strong>Ledger shakedown:</strong> Empire soldiers delay a caravan at the toll gate; the player can bribe, attack, steal during confusion, or escort the wagon away.</li><li><strong>Tower witness:</strong> a scout watches a robbery from the tower and flees north; catching them prevents later retaliation.</li></ul><h2 id="traversal-and-camera-notes" tabindex="-1">Traversal and camera notes <a class="header-anchor" href="#traversal-and-camera-notes" aria-label="Permalink to &quot;Traversal and camera notes&quot;">​</a></h2><ul><li>Keep the main road at least 4 meters wide in gameplay scale so wagons, guards, and the player can share it.</li><li>Hedges should stop line of sight but not create tight camera tunnels.</li><li>The dry riverbed should have ramps at both ends and no sharp lip that catches the capsule controller.</li><li>The tower and overlook are optional vertical beats; the first greybox can keep them as blocked props.</li></ul><h2 id="streaming-and-save-notes" tabindex="-1">Streaming and save notes <a class="header-anchor" href="#streaming-and-save-notes" aria-label="Permalink to &quot;Streaming and save notes&quot;">​</a></h2><ul><li>Suggested cells: <code>velya_farms</code>, <code>velya_inn</code>, <code>velya_riverbed</code>, <code>velya_toll_gate</code>, <code>velya_watchtower</code>.</li><li>Save payload should track active caravan state: route progress, wagon health, cargo status, and surviving guards.</li><li>Later reputation flags can attach to the road: Empire wanted level, elf favor, town merchant trust, villain witness escaped.</li></ul><h2 id="asset-list" tabindex="-1">Asset list <a class="header-anchor" href="#asset-list" aria-label="Permalink to &quot;Asset list&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Asset</th><th>Priority</th><th>Notes</th></tr></thead><tbody><tr><td>Low-poly wagon</td><td>High</td><td>Needs cargo sockets and damaged state.</td></tr><tr><td>Cargo crates and salt sacks</td><td>High</td><td>Lootable, stackable silhouettes.</td></tr><tr><td>Toll gate</td><td>High</td><td>Barrier arm, ledger table, Empire banner.</td></tr><tr><td>Burned inn shell</td><td>Medium</td><td>Spawn landmark and future shop shell.</td></tr><tr><td>Shrine stones</td><td>Medium</td><td>Small unique landmark with readable shape.</td></tr><tr><td>Watchtower</td><td>Medium</td><td>Can be non-climbable at first.</td></tr><tr><td>Hedge/fence kit</td><td>Medium</td><td>Reused across human lands.</td></tr></tbody></table><h2 id="open-implementation-questions" tabindex="-1">Open implementation questions <a class="header-anchor" href="#open-implementation-questions" aria-label="Permalink to &quot;Open implementation questions&quot;">​</a></h2><ul><li>Does caravan robbery immediately mark the player hostile to Empire, or only when witnesses survive?</li><li>Should the first playable version include mounted road blockers, or fake them as static props?</li><li>How much loot can be carried before inventory weight or movement penalties exist?</li></ul>',28)])])}const m=e(o,[["render",s]]);export{p as __pageData,m as default};
